// === READ API KEYS FROM keys.json ===
const fs = require('fs');
let keys;
try {
  keys = JSON.parse(fs.readFileSync('/home/node/jobsearch-keys.json', 'utf8'));
} catch(e) {
  throw new Error('Cannot read keys.json: ' + e.message + '. Check Docker volume mount and restart.');
}

if (!keys.rapidApiKey || keys.rapidApiKey.trim().startsWith('YOUR_')) {
  throw new Error('keys.json: rapidApiKey not set. Fill in keys.json and restart Docker.');
}
if (!keys.openAiApiKey || keys.openAiApiKey.startsWith('YOUR_')) {
  throw new Error('keys.json: openAiApiKey not set. Fill in keys.json and restart Docker.');
}
if (!keys.apifyToken || keys.apifyToken.startsWith('YOUR_')) {
  throw new Error('keys.json: apifyToken not set. Fill in keys.json and restart Docker.');
}

// === READ RESUME FROM PDF ===
const rawText = $input.first().json.text;

if (!rawText || rawText.trim().length < 50) {
  throw new Error('Resume PDF appears empty or too short.');
}

// Clean up null characters introduced by PDF extraction
const resumeText = rawText.replace(/\u0000/g, '').trim();

const baseConfig = {
  minScore: 70,
  yourEmail: 'YOUR_EMAIL@gmail.com',
  spreadsheetId: 'YOUR_GOOGLE_SHEET_ID',
  openAiApiKey: keys.openAiApiKey,
  rapidApiKey: keys.rapidApiKey.trim(),
  apifyToken: keys.apifyToken,
  resumeText: resumeText
};

// 7 targeted JSearch searches: .NET/C#/Azure/Microservices roles, Bangalore only
const queries = [
  '.NET Developer Bangalore India',
  'Backend Engineer .NET Bangalore India',
  'Microservices .NET Backend Engineer Bangalore India',
  'SDE 2 .NET Bangalore India',
  'Senior Software Engineer .NET Bangalore India',
  'Azure .NET Developer Bangalore India',
  'Software Engineer II .NET Bangalore India'
];

return queries.map(function(q) {
  return { json: Object.assign({}, baseConfig, { searchQuery: q }) };
});

const config = $input.first().json;

return [
  {
    json: {
      apifyToken: config.apifyToken,
      naukriJobTitle: '.NET Developer',
      naukriLocation: 'Bangalore'
    }
  }
];

const config = $input.first().json;

return [
  {
    json: {
      apifyToken: config.apifyToken,
      naukriJobTitle: 'C# Developer',
      naukriLocation: 'Bangalore'
    }
  }
];

const allItems = $input.all();
let allJobs = [];

function normalizeUrl(url) {
  if (!url) return '';
  try {
    const u = new URL(url);
    return (u.hostname + u.pathname).toLowerCase().replace(/\/$/, '');
  } catch(e) { return url.toLowerCase().trim().substring(0, 200); }
}

function hashJob(company, title, applyLink) {
  const raw = applyLink ? normalizeUrl(applyLink) : ((company || '').toLowerCase().trim() + '|' + (title || '').toLowerCase().trim());
  let hash = 0;
  for (let i = 0; i < raw.length; i++) {
    const char = raw.charCodeAt(i);
    hash = ((hash << 5) - hash) + char;
    hash = hash & hash;
  }
  return 'JOB_' + Math.abs(hash).toString(36);
}

function parseNaukriJob(job) {
  const company = job.companyName || job.company || 'Unknown Company';
  const title = job.jobTitle || job.title || job.positionName || 'Unknown Title';
  const applyLink = job.apply_link || job.jobUrl || job.url || job.applyLink || '';
  return {
    jobId: hashJob(company, title, applyLink),
    title,
    company,
    location: job.location || job.jobLocation || job.city || 'Bangalore',
    description: (job.jobDescription || job.description || job.jobSummary || '').substring(0, 3000),
    postedDate: job.datePosted || job.postedDate || job.posted || job.date || 'Unknown',
    applyLink,
    source: 'Naukri',
    salary: job.salary || job.salaryRange || job.ctc || 'Not listed',
    schedule: job.employmentType || job.jobType || job.workplaceType || ''
  };
}

for (const item of allItems) {
  if (item.json.data && Array.isArray(item.json.data)) {
    // JSearch format: single response item with data[] array
    const jobs = item.json.data;
    const parsed = jobs.map(job => {
      const location = [job.job_city, job.job_state].filter(Boolean).join(', ') || 'Bangalore';
      let salary = 'Not listed';
      if (job.job_min_salary && job.job_max_salary) {
        salary = `${job.job_salary_currency || ''} ${job.job_min_salary}-${job.job_max_salary} ${job.job_salary_period || ''}`.trim();
      }
      const applyLink = job.job_apply_link || job.job_google_link || '';
      return {
        jobId: hashJob(job.employer_name, job.job_title, applyLink),
        title: job.job_title || 'Unknown Title',
        company: job.employer_name || 'Unknown Company',
        location,
        description: (job.job_description || '').substring(0, 3000),
        postedDate: job.job_posted_at_datetime_utc ? job.job_posted_at_datetime_utc.split('T')[0] : 'Unknown',
        applyLink,
        source: job.job_publisher || 'JSearch',
        salary,
        schedule: job.job_employment_type || ''
      };
    });
    allJobs.push(...parsed);
  } else if (Array.isArray(item.json)) {
    // Apify/Naukri format — full array in one item (fallback)
    allJobs.push(...item.json.map(parseNaukriJob));
  } else if (item.json.title || item.json.jobTitle || item.json.positionName || item.json.companyName) {
    // Individual Naukri/Apify job object — n8n HTTP Request unpacks JSON arrays into individual items
    allJobs.push(parseNaukriJob(item.json));
  }
}

if (allJobs.length === 0) {
  throw new Error('No jobs found from any source. Check your API keys and queries.');
}

return { json: { jobs: allJobs, totalFound: allJobs.length } };

const allResults = $input.all();
const uniqueJobs = new Map();

for (const result of allResults) {
  const jobs = result.json.jobs || [];
  for (const job of jobs) {
    if (!uniqueJobs.has(job.jobId)) {
      uniqueJobs.set(job.jobId, job);
    }
  }
}

return Array.from(uniqueJobs.values()).map(job => ({ json: job }));

// Collapse N job items into 1 so Read Existing Jobs runs exactly once (not per-job)
const jobs = $input.all().map(item => item.json);
return [{ json: { jobs, count: jobs.length } }];

function normalizeUrl(url) {
  if (!url) return '';
  try {
    const u = new URL(url);
    return (u.hostname + u.pathname).toLowerCase().replace(/\/$/, '');
  } catch(e) { return url.toLowerCase().trim().substring(0, 200); }
}

const all = $input.all();

// Separate by shape: jobs item has {jobs:[...], count:N}, sheet rows have {Apply Link:...}
const jobsItem = all.find(i => Array.isArray(i.json.jobs));
const sheetRows = all.filter(i => !Array.isArray(i.json.jobs));

const jobs = jobsItem ? jobsItem.json.jobs : [];

const seenLinks = new Set(
  sheetRows.map(r => normalizeUrl(r.json['Apply Link'] || '')).filter(Boolean)
);
const seenTitles = new Set(
  sheetRows.map(r => ((r.json['Company'] || '') + '|' + (r.json['Job Title'] || '')).toLowerCase().trim()).filter(s => s !== '|')
);

const newJobs = jobs.filter(job => {
  const link = normalizeUrl(job.applyLink || '');
  if (link) return !seenLinks.has(link);
  const key = ((job.company || '') + '|' + (job.title || '')).toLowerCase().trim();
  return !seenTitles.has(key);
});

if (newJobs.length === 0) {
  throw new Error('No new jobs this week \u2014 all ' + jobs.length + ' results were already seen in previous runs.');
}

return newJobs.map(job => ({ json: job }));

﻿const items = $input.all();

// Non-.NET stack patterns in job title — .NET/C# anywhere in title overrides
// Matches both "Java Developer" AND "Software Engineer - Java", "Java API Engineer"
const nonDotNetTitlePatterns = [
  // Direct stack mentions (anywhere in title)
  /\bjava\b(?!\s*script)/i,
  /\bnode\.?js\b/i,
  /\bpython\b/i,
  /\bruby\s*(developer|engineer|on rails)\b/i,
  /\bgolang\b/i,
  /\bgo\s+(developer|engineer|backend)\b/i,
  /\bphp\b/i,
  /\bandroid\s*(developer|engineer|sde|framework)\b/i,
  /\bios\s*(developer|engineer|sde)\b/i,
  /\bflutter\s*(developer|engineer)\b/i,
  /\breact\s*native\b/i,
  /\bmobile\s*(ui|developer|engineer|sde)\b/i,
  /\bui\s*developer\b/i,
  /\bangular\s*(developer|engineer|consultant)\b/i,
  /\bvue\s*(developer|engineer)\b/i,
  /\blaravel\b/i,
  /\bdata\s*(scientist|analyst)\b/i,
  /\bmachine\s*learning\b/i,
  /\bgen\s*ai\b/i,
  /\bsalesforce\b/i,
  /\bsap\b/i,
  /\babap\b/i,
  /\bsql\s+(developer|engineer)\b/i,
  /\b(c\+\+|cpp)\b/i,
  /\bkernel\b/i,
  /\blinux\s+(kernel|infrastructure|engineer)\b/i,
  /\bavionics\b/i,
  /\bembedded\b/i,
  /\baveva\b/i,
  /\btemenos\b/i,
  /\bworkday\b/i,
  /\blabware\b/i,
  /\bgenesys\b/i,
  /\bservicenow\b/i,
  /\b(rpa|ui\/ux)\b/i,
  // Role types we don't want
  /\b(test|qa|sdet)\s*(engineer|lead|specialist|automation)\b/i,
  /\btest\s*module\s*lead\b/i,
  /\bdevops\s*(engineer|specialist)\b/i,
  /\bdevsecops\b/i,
  /\bsre\b/i,
  /\b(ci\/cd|pipeline)\b/i,
  /\bcloud\s*(engineer|architect|operations|ops)\b/i,
  /\bnetwork(ing)?\s*engineer\b/i,
  /\bsecurity\s*engineer\b/i,
  /\bsupport\s*(engineer|specialist|l[12])\b/i,
  /\bbusiness\s*(analyst|consultant)\b/i,
  /\bproject\s*manager\b/i,
  /\bprogram\s*manager\b/i,
  /\bservice\s*management\b/i,
  /\bsoftware\s*inventory\b/i,
  /\bcustom\s*software\s*engineer\b/i,
  /\bnugenesis\b/i,
  /\bfenergo\b/i,
  /\bsprinklr\b/i,
];

const dotNetTitlePatterns = [/\.net/i, /\bc#\b/i, /\basp\.net/i, /\bdotnet\b/i, /\bdot\s*net\b/i];

const tooJuniorPatterns = [
  /fresher/i,
  /internship/i,
  /\bintern\b/i,
  /\b(junior|jr\.?)\s*(developer|engineer|sde|programmer)\b/i,
  /\bgraduate\s*(engineer|developer|trainee)\b/i,
  /\btrainee\s*(engineer|developer|software)\b/i,
  /\b0[-]?[12]\s*years?\b/i,
  /\bsoftware\s*engineer\s*i\b(?!\s*[i])/i,
  /\bsde[-\s]?[1i]\b(?!\s*[i])/i,
];

const tooSeniorPatterns = [
  /\bprincipal\s*(engineer|architect|developer|software)\b/i,
  /\bstaff\s*(engineer|developer|software|architect)\b/i,
  /\b(vp|vice president)\s*(of|,)?\s*(engineering|technology|software)\b/i,
  /\b(cto|chief\s*technology\s*officer)\b/i,
  /\bengineering\s*director\b/i,
  /\b(sr\.?\s*manager|sr\.?\s*director)\b/i,
  /\bdirector,?\s*software/i,
  /\bsde\s*iii\b/i,
  /\bsde\s*3\b/i,
];

const otherCityPattern = /(mumbai|hyderabad|chennai|pune|delhi|gurugram|gurgaon|noida|kolkata|ahmedabad|jaipur|indore|coimbatore)/i;

// Description-level non-.NET stack check (catches niche/obscure roles)
const descNonDotNetPatterns = [
  /\bprimary\s+stack[:\s]+java\b/i,
  /\bjava\s+is\s+(the\s+)?(primary|main|required|mandatory)\b/i,
  /\bpython\s+is\s+(the\s+)?(primary|main|required|mandatory)\b/i,
];

function seniorityScore(title) {
  if (/(senior|sr\.?|lead|tech lead)/i.test(title)) return 3;
  if (/\b(sde\s*[23]|se\s*[23]|engineer\s*(ii|iii)|developer\s*(ii|iii)|software\s*engineer\s*(2|3))\b/i.test(title)) return 2;
  return 1;
}

const filtered = [];
const removed = { nonDotNet: [], tooJunior: [], tooSenior: [], overExperienced: 0, offLocation: 0, shortDesc: 0, descNonDotNet: 0 };

for (const item of items) {
  const title = item.json.title || '';
  const desc = item.json.description || '';
  const location = item.json.location || '';

  const hasDotNetInTitle = dotNetTitlePatterns.some(p => p.test(title));
  if (!hasDotNetInTitle && nonDotNetTitlePatterns.some(p => p.test(title))) {
    removed.nonDotNet.push(title);
    continue;
  }

  // Junior check yields to .NET-in-title (e.g. "Lead Software Engineer I (C#.NET)" should pass)
  if (!hasDotNetInTitle && tooJuniorPatterns.some(p => p.test(title))) {
    removed.tooJunior.push(title);
    continue;
  }

  if (tooSeniorPatterns.some(p => p.test(title))) {
    removed.tooSenior.push(title);
    continue;
  }

  // Description-level non-.NET check (only if .NET not in title — otherwise trust title)
  if (!hasDotNetInTitle && descNonDotNetPatterns.some(p => p.test(desc))) {
    removed.descNonDotNet++;
    continue;
  }

  const expMatch = desc.match(/(\d+)\s*\+\s*years?\s*(of\s+)?(experience|exp)/i) ||
                   desc.match(/(?:minimum|at\s+least|min\.?)\s*(\d+)\s*years?\s*(of\s+)?(experience|exp)/i) ||
                   desc.match(/(\d+)\s*years?\s*(of\s+)?(experience|exp)\s*(?:minimum|required|min)/i);
  if (expMatch) {
    const minYears = parseInt(expMatch[1]);
    if (minYears >= 8) { removed.overExperienced++; continue; }
  }

  const hasBangalore = /(bangalore|bengaluru)/i.test(location);
  const hasOtherCity = otherCityPattern.test(location);
  if (!hasBangalore && hasOtherCity) { removed.offLocation++; continue; }

  if (desc.length < 150) { removed.shortDesc++; continue; }

  filtered.push(item);
}

const COMPANY_CAP = 3;
const byCompany = {};
for (const item of filtered) {
  const co = (item.json.company || 'unknown')
    .toLowerCase()
    .replace(/\s+(india|pvt|ltd|limited|inc|technologies|tech|solutions|services).?/gi, '')
    .trim();
  if (!byCompany[co]) byCompany[co] = [];
  byCompany[co].push(item);
}

const capped = [];
const capRemoved = [];
for (const [co, coItems] of Object.entries(byCompany)) {
  if (coItems.length <= COMPANY_CAP) {
    capped.push(...coItems);
  } else {
    const sorted = [...coItems].sort((a, b) => seniorityScore(b.json.title || '') - seniorityScore(a.json.title || ''));
    capped.push(...sorted.slice(0, COMPANY_CAP));
    capRemoved.push(co.slice(0, 20) + ' (dropped ' + (coItems.length - COMPANY_CAP) + ')');
  }
}

if (capped.length === 0) {
  throw new Error('All ' + items.length + ' jobs filtered. Non-.NET: ' + removed.nonDotNet.length + ', Junior: ' + removed.tooJunior.length + ', Senior: ' + removed.tooSenior.length + ', Over-exp: ' + removed.overExperienced + ', Off-location: ' + removed.offLocation + ', Stubs: ' + removed.shortDesc + '.');
}

console.log('Stack filter: ' + items.length + ' -> ' + capped.length + '. Removed: ' + removed.nonDotNet.length + ' non-.NET, ' + removed.tooJunior.length + ' junior, ' + removed.tooSenior.length + ' senior, ' + removed.overExperienced + ' over-exp, ' + removed.offLocation + ' off-location, ' + removed.shortDesc + ' stubs, ' + removed.descNonDotNet + ' desc-non-.NET. Company cap: ' + (capRemoved.length > 0 ? capRemoved.join('; ') : 'none'));
if (removed.nonDotNet.length > 0) console.log('Non-.NET removed:', removed.nonDotNet.slice(0, 5).join(' | '));

return capped;

// Prepare OpenAI payload for each job
const config = $('Set Job Preferences').first().json;

return $input.all().map(item => {
  const job = item.json;
  const resume = config.resumeText || '';
  const jobDesc = (job.description || '').substring(0, 3000);

  const aiPayload = JSON.stringify({
    model: 'gpt-4o-mini',
    messages: [
      {
        role: 'system',
        content: 'You are an expert technical recruiter specializing in .NET/backend engineering roles in India. Score job-resume matches for a Software Engineer II with 5+ years of experience.

CANDIDATE PROFILE:
- Core Stack: C#, .NET Core, ASP.NET Core, Entity Framework, ReactJS (secondary)
- Data and Messaging: SQL Server, MongoDB, Redis, Apache Kafka, RabbitMQ
- Cloud and DevOps: Azure DevOps CI/CD, Docker, AWS S3, Nginx
- Architecture: Microservices, Distributed Systems, Event-Driven Design, TDD
- Domains: Fintech/BFSI (fund administration, client payments, reconciliation) + Healthcare IT
- Seniority: 5 years total, currently Software Engineer II at a Healthcare company, previously at a Fintech/Fund Administration company

SCORING INSTRUCTIONS — follow these 4 steps in order:
Step 1: Assign a BASE score from the rubric below.
Step 2: ADD 8 for each boost condition that applies (max +16 total).
Step 3: SUBTRACT 15 for each penalty condition that applies.
Step 4: Clamp to 0-100. This is the final score field.

BASE SCORE RUBRIC:
- 82-88: Strong .NET/C# backend role, solid architecture requirements (microservices, distributed systems, or event-driven design), 3-6 years required. This is where most good matches start.
- 70-81: Good .NET/C# backend role in Bangalore, 3-7 years required, backend stack match, no specific architecture requirement.
- 50-69: Partial — .NET present but role is frontend-heavy, or different primary stack with some .NET/C# overlap.
- 0-49: No .NET or C# requirement, entry-level only, purely frontend, or Java/Python-only.

BOOST +8 for each that applies (max two boosts = +16):
- Role is in Fintech, BFSI, Banking, Payments, Insurance, Healthcare, or MedTech domain
- Requires Azure or Azure DevOps experience
- Requires Kafka, RabbitMQ, Redis, or event-driven messaging architecture
- Requires microservices or distributed systems architecture design

PENALIZE -15 for each that applies:
- Role is primarily frontend (React/Angular/Vue is the main requirement, backend is secondary)
- Requires less than 2 years experience
- Requires more than 7 years experience
- No mention of .NET, C#, or backend development anywhere in the description

SCORING EXAMPLES (use these to calibrate):
- .NET Core backend at a Fintech payments company, 4-5 years, microservices mentioned → base 86 + Fintech +8 + microservices +8 = 102 → capped at 100
- Solid .NET backend at a product company, 3-5 years, Azure DevOps required → base 83 + Azure +8 = 91
- Good .NET backend, Kafka/RabbitMQ required, 4-6 years → base 82 + messaging +8 = 90
- Good .NET backend, no boosts, 4-6 years → base 78, no boosts → 78
- .NET role but requires 8+ years → base 80 − penalty 15 = 65
- React-heavy full stack, .NET is secondary → base 60 − frontend penalty 15 = 45

Return a JSON object with exactly these fields: score (number 0-100), matchReason (string 2-3 sentences explaining the specific match and which boosts or penalties were applied), missingSkills (array of strings), keyMatchingSkills (array of strings), experienceFit (one of: good, overqualified, underqualified), recommendation (one of: strong-apply, apply, maybe, skip).'
      },
      {
        role: 'user',
        content: 'Analyze the match between this resume and job posting.

RESUME:
' + resume + '

JOB POSTING:
' + jobDesc
      }
    ],
    temperature: 0.1,
    response_format: { type: 'json_object' }
  });

  return {
    json: {
      ...job,
      openAiApiKey: config.openAiApiKey,
      aiPayload
    }
  };
});

const groqResponse = $input.item.json;
const job = $('Prepare Score Request').item.json;

const aiText = groqResponse.choices?.[0]?.message?.content || '{}';
let p = {};
try {
  p = JSON.parse(aiText);
} catch(e) {
  // Extract JSON block in case model wrapped it in markdown or added extra text
  const match = aiText.match(/{[sS]*}/);
  if (match) {
    try { p = JSON.parse(match[0]); } catch(e2) {}
  }
}

const score = typeof p.score === 'number' ? p.score : (parseInt(p.score) || 0);

return {
  json: {
    jobId: job.jobId,
    title: job.title,
    company: job.company,
    location: job.location,
    description: job.description,
    postedDate: job.postedDate,
    applyLink: job.applyLink,
    source: job.source,
    salary: job.salary,
    schedule: job.schedule,
    score,
    matchReason: p.matchReason || '',
    missingSkills: Array.isArray(p.missingSkills) ? p.missingSkills : [],
    keyMatchingSkills: Array.isArray(p.keyMatchingSkills) ? p.keyMatchingSkills : [],
    experienceFit: p.experienceFit || 'unknown',
    recommendation: p.recommendation || 'skip'
  }
};

const items = $input.all();
const minScore = $('Set Job Preferences').first().json.minScore || 50;

const matched = items.filter(item => (item.json.score || 0) >= minScore);

if (matched.length === 0) {
  throw new Error(`No jobs scored above ${minScore}. Top score was ${Math.max(...items.map(i => i.json.score || 0))}. Try lowering minScore in Set Job Preferences.`);
}

return matched;

// Prepare OpenAI payload for cover letter generation
const config = $('Set Job Preferences').first().json;

return $input.all().map(item => {
  const job = item.json;
  const resume = config.resumeText || '';
  const jobDesc = (job.description || '').substring(0, 3000);

  const aiPayload = JSON.stringify({
    model: 'gpt-4o-mini',
    messages: [
      {
        role: 'system',
        content: 'You are an expert career coach writing cover letters for a Software Engineer II with 5+ years of backend .NET experience.\n\nCANDIDATE: Backend-focused Full Stack Developer specializing in .NET Core, microservices, and distributed systems. Experience across Fintech (fund administration, client payments, Redis caching, microservice migrations) and Healthcare IT. Strong in system performance optimization, CI/CD pipelines, and cross-functional delivery.\n\nWrite a concise, professional cover letter (under 280 words) tailored to the specific job posting. Structure: opening hook matching the role, 2-3 sentences on relevant technical experience with 1-2 specific achievements from the background (e.g., improved response times 60% via Redis caching, raised test coverage to 85% with TDD, cut build times 15% via .NET 6-to-8 migration), closing with enthusiasm for the role and company. Plain text only, no bullet points, no placeholders, no Dear Hiring Manager — address the company by name if mentioned in the job posting.'
      },
      {
        role: 'user',
        content: 'Write a professional cover letter.\n\nRESUME:\n' + resume + '\n\nJOB:\n' + jobDesc
      }
    ],
    temperature: 0.7
  });

  return {
    json: {
      ...job,
      openAiApiKey: config.openAiApiKey,
      aiPayload
    }
  };
});

const groqResponse = $input.item.json;
const job = $('Prepare Cover Letter').item.json;

const coverLetter = groqResponse.choices?.[0]?.message?.content || 'Cover letter generation failed.';

return {
  json: {
    ...job,
    coverLetter: coverLetter.trim(),
    processedDate: new Date().toISOString().split('T')[0]
  }
};

const items = $input.all();
const config = $('Set Job Preferences').first().json;
const today = new Date().toLocaleDateString('en-US', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' });

const getScore = j => Number(j['Match Score'] || j.score || 0);

if (items.length === 0) {
  return {
    json: {
      subject: `Job Search: No new matches found - ${today}`,
      htmlBody: `<html><body style="font-family: Arial, sans-serif;"><h2>Job Search Report - ${today}</h2><p>No new jobs matched your criteria (minimum score: ${config.minScore}).</p></body></html>`,
      matchCount: 0,
      topScore: 0,
      yourEmail: config.yourEmail
    }
  };
}

// Pull keyMatchingSkills from Attach Cover Letter (not persisted to Google Sheets)
const fullJobItems = $('Attach Cover Letter').all();
const merged = items.map((item, idx) => ({
  ...item.json,
  keyMatchingSkills: fullJobItems[idx]?.json?.keyMatchingSkills || []
}));
const sorted = merged.sort((a, b) => getScore(b) - getScore(a));
const topScore = getScore(sorted[0]);

const jobRows = sorted.map(j => {
  const title = j['Job Title'] || j.title || 'Unknown Title';
  const company = j['Company'] || j.company || 'Unknown';
  const location = j['Location'] || j.location || 'Not specified';
  const score = getScore(j);
  const recommendation = j['Recommendation'] || j.recommendation || 'skip';
  const matchReason = j['Match Reason'] || j.matchReason || '';
  const missingSkills = j['Missing Skills'] || (j.missingSkills ? (Array.isArray(j.missingSkills) ? j.missingSkills.join(', ') : j.missingSkills) : '');
  const applyLink = j['Apply Link'] || j.applyLink || '#';
  const coverLetter = j['Cover Letter'] || j.coverLetter || '';
  const source = j.source || 'Google Jobs';
  const salary = j.salary || 'Not listed';
  const scoreColor = score >= 85 ? '#27ae60' : score >= 70 ? '#f39c12' : '#e74c3c';
  const recBadge = recommendation === 'strong-apply' ? 'Strong Apply' : recommendation === 'apply' ? 'Apply' : recommendation === 'maybe' ? 'Maybe' : 'Skip';
  const keySkillsArr = Array.isArray(j.keyMatchingSkills) ? j.keyMatchingSkills : [];
  const keySkillTags = keySkillsArr.slice(0, 5).map(s =>
    `<span style="background:#27ae60;color:white;padding:2px 7px;border-radius:10px;font-size:11px;margin-right:4px;">${s}</span>`
  ).join('');
  return `<tr style="border-bottom: 1px solid #eee;"><td style="padding: 12px;"><strong>${title}</strong><br><span style="color: #666;">${company} - ${location}</span><br><span style="color: #888; font-size: 12px;">${source} | ${salary}</span></td><td style="padding: 12px; text-align: center;"><span style="background: ${scoreColor}; color: white; padding: 4px 12px; border-radius: 12px; font-weight: bold;">${score}</span></td><td style="padding: 12px; text-align: center;">${recBadge}</td><td style="padding: 12px;"><a href="${applyLink}" style="background: #3498db; color: white; padding: 8px 16px; border-radius: 4px; text-decoration: none;">Apply</a></td></tr><tr><td colspan="4" style="padding: 8px 12px; background: #f9f9f9;"><strong>Why it matches:</strong> ${matchReason}<br>${keySkillTags ? '<strong>Key skills:</strong> ' + keySkillTags + '<br>' : ''}${missingSkills ? '<strong>Missing:</strong> ' + missingSkills : ''}</td></tr><tr><td colspan="4" style="padding: 8px 12px; background: #f0f7ff;"><details><summary style="cursor: pointer; font-weight: bold;">Cover Letter</summary><div style="white-space: pre-wrap; margin-top: 8px; padding: 12px; background: white; border: 1px solid #ddd; border-radius: 4px;">${coverLetter}</div></details></td></tr>`;
}).join('');

const htmlBody = `<html><body style="font-family: Arial, sans-serif; max-width: 800px; margin: 0 auto;"><div style="background: linear-gradient(135deg, #667eea 0%, #764ba2 100%); padding: 24px; border-radius: 8px 8px 0 0;"><h1 style="color: white; margin: 0;">Job Search Report</h1><p style="color: rgba(255,255,255,0.8); margin: 8px 0 0;">${today}</p></div><div style="background: #f5f5f5; padding: 16px;"><span style="background: white; padding: 12px 24px; border-radius: 8px; margin-right: 16px;"><strong style="font-size: 24px; color: #3498db;">${sorted.length}</strong> Matches</span><span style="background: white; padding: 12px 24px; border-radius: 8px;"><strong style="font-size: 24px; color: #27ae60;">${topScore}</strong> Top Score</span></div><table style="width: 100%; border-collapse: collapse; background: white;"><thead><tr style="background: #ecf0f1;"><th style="padding: 12px; text-align: left;">Job</th><th style="padding: 12px; text-align: center;">Score</th><th style="padding: 12px; text-align: center;">Action</th><th style="padding: 12px;">Link</th></tr></thead><tbody>${jobRows}</tbody></table><div style="padding: 16px; text-align: center; color: #888; font-size: 12px;">Generated by n8n Job Search Automation | Min score: ${config.minScore}</div></body></html>`;

return {
  json: {
    subject: `${sorted.length} Job Matches (Top: ${topScore}/100) - ${new Date().toLocaleDateString('en-US', { month: 'short', day: 'numeric' })}`,
    htmlBody,
    matchCount: sorted.length,
    topScore,
    yourEmail: config.yourEmail
  }
};

const emailData = $('Build Email Digest').first().json;
return {
  json: {
    success: true,
    message: 'Job search automation completed!',
    matchCount: emailData.matchCount || 0,
    topScore: emailData.topScore || 0,
    emailSent: true,
    sentTo: emailData.yourEmail || 'unknown',
    timestamp: new Date().toISOString()
  }
};
